// Security: Input validation and sanitization
class InputValidator {
  static validateBatchRequest(body) {
    if (!body || typeof body !== "object") {
      throw new Error("Invalid request body");
    }

    const allowedFields = ["databaseId", "containerId", "query", "batchSize", "continuationToken", "processingType"];
    const unknownFields = Object.keys(body).filter(k => !allowedFields.includes(k));
    if (unknownFields.length > 0) {
      throw new Error(`Unknown fields: ${unknownFields.join(", ")}`);
    }

    if (body.databaseId && !/^[a-zA-Z0-9_-]{1,256}$/.test(body.databaseId)) {
      throw new Error("Invalid databaseId format");
    }

    if (body.containerId && !/^[a-zA-Z0-9_-]{1,256}$/.test(body.containerId)) {
      throw new Error("Invalid containerId format");
    }

    if (body.batchSize !== undefined) {
      const batchSize = parseInt(body.batchSize, 10);
      if (isNaN(batchSize) || batchSize < 1 || batchSize > 10000) {
        throw new Error("batchSize must be between 1 and 10000");
      }
      body.batchSize = batchSize;
    }

    // Prevent SQL injection in Cosmos DB queries
    if (body.query) {
      const forbidden = [";", "--", "/*", "*/", "xp_", "exec(", "execute("];
      const lowerQuery = body.query.toLowerCase();
      for (const token of forbidden) {
        if (lowerQuery.includes(token)) {
          throw new Error("Potentially malicious query detected");
        }
      }
    }

    const allowedProcessingTypes = ["transform", "aggregate", "validate", "enrich"];
    if (body.processingType && !allowedProcessingTypes.includes(body.processingType)) {
      throw new Error(`Invalid processingType. Allowed: ${allowedProcessingTypes.join(", ")}`);
    }

    return body;
  }
}

// Security: Rate limiting and request tracking
class RequestTracker {
  constructor() {
    this.activeRequests = new Map();
    this.requestCounts = new Map();
    this.maxConcurrentPerClient = 3;
    this.maxRequestsPerMinute = 10;
  }

  checkRateLimit(clientId) {
    const now = Date.now();
    const windowMs = 60000;

    if (!this.requestCounts.has(clientId)) {
      this.requestCounts.set(clientId, []);
    }

    const timestamps = this.requestCounts.get(clientId).filter(t => now - t < windowMs);
    this.requestCounts.set(clientId, timestamps);

    if (timestamps.length >= this.maxRequestsPerMinute) {
      throw new Error("Rate limit exceeded");
    }

    const activeCount = this.activeRequests.get(clientId) || 0;
    if (activeCount >= this.maxConcurrentPerClient) {
      throw new Error("Too many concurrent requests");
    }

    timestamps.push(now);
    this.activeRequests.set(clientId, activeCount + 1);
  }

  releaseRequest(clientId) {
    const count = this.activeRequests.get(clientId) || 1;
    this.activeRequests.set(clientId, Math.max(0, count - 1));
  }
}

// Checkpoint manager for resumable processing
class CheckpointManager {
  constructor(cosmosClient, databaseId) {
    this.cosmosClient = cosmosClient;
    this.databaseId = databaseId;
    this.checkpointContainerId = "batch-checkpoints";
  }

  async initialize() {
    const { database } = await this.cosmosClient.databases.createIfNotExists({ id: this.databaseId });
    await database.containers.createIfNotExists({
      id: this.checkpointContainerId,
      partitionKey: { paths: ["/jobId"] },
      defaultTtl: 86400 // 24 hours TTL for checkpoints
    });
  }

  async saveCheckpoint(jobId, checkpoint) {
    const container = this.cosmosClient
      .database(this.databaseId)
      .container(this.checkpointContainerId);

    await container.items.upsert({
      id: jobId,
      jobId: jobId,
      ...checkpoint,
      updatedAt: new Date().toISOString()
    });
  }

  async getCheckpoint(jobId) {
    try {
      const container = this.cosmosClient
        .database(this.databaseId)
        .container(this.checkpointContainerId);

      const { resource } = await container.item(jobId, jobId).read();
      return resource;
    } catch (error) {
      if (error.code === 404) return null;
      throw error;
    }
  }

  async deleteCheckpoint(jobId) {
    try {
      const container = this.cosmosClient
        .database(this.databaseId)
        .container(this.checkpointContainerId);

      await container.item(jobId, jobId).delete();
    } catch (error) {
      if (error.code !== 404) throw error;
    }
  }
}

// Batch processor with timeout awareness
class BatchProcessor {
  constructor(cosmosClient, config, context) {
    this.cosmosClient = cosmosClient;
    this.config = config;
    this.context = context;
    this.checkpointManager = new CheckpointManager(cosmosClient, config.databaseId);
    this.startTime = Date.now();
    this.maxExecutionMs = 9 * 60 * 1000; // 9 minutes - leave 1 minute buffer
    this.processedCount = 0;
    this.errorCount = 0;
    this.errors = [];
    this.isShuttingDown = false;
  }

  getRemainingTimeMs() {
    return this.maxExecutionMs - (Date.now() - this.startTime);
  }

  shouldContinueProcessing() {
    // Reserve 30 seconds for cleanup and checkpoint saving
    return !this.isShuttingDown && this.getRemainingTimeMs() > 30000;
  }

  async initialize() {
    await this.checkpointManager.initialize();
  }

  async processDataset(jobId) {
    const container = this.cosmosClient
      .database(this.config.databaseId)
      .container(this.config.containerId);

    // Check for existing checkpoint to resume
    let checkpoint = await this.checkpointManager.getCheckpoint(jobId);
    let continuationToken = checkpoint?.continuationToken || this.config.continuationToken || undefined;
    this.processedCount = checkpoint?.processedCount || 0;

    const query = this.config.query || "SELECT * FROM c";
    const batchSize = this.config.batchSize || 1000;

    this.context.log(`Starting batch processing job ${jobId}. Resuming from count: ${this.processedCount}`);

    let hasMoreResults = true;
    let batchNumber = checkpoint?.batchNumber || 0;

    while (hasMoreResults && this.shouldContinueProcessing()) {
      try {
        const queryIterator = container.items.query(query, {
          maxItemCount: batchSize,
          continuationToken: continuationToken,
          bufferItems: true,
          maxDegreeOfParallelism: 4
        });

        const { resources: items, continuationToken: nextToken, requestCharge } =
          await queryIterator.fetchNext();

        if (!items || items.length === 0) {
          hasMoreResults = false;
          break;
        }

        this.context.log(`Processing batch ${batchNumber}: ${items.length} items (RU charge: ${requestCharge})`);

        // Process items in parallel with concurrency control
        await this.processItemsBatch(items, container);

        continuationToken = nextToken;
        hasMoreResults = !!nextToken;
        batchNumber++;

        // Save checkpoint after each batch
        await this.checkpointManager.saveCheckpoint(jobId, {
          continuationToken: continuationToken,
          processedCount: this.processedCount,
          batchNumber: batchNumber,
          status: hasMoreResults ? "in_progress" : "completed",
          lastProcessedAt: new Date().toISOString()
        });

        // Adaptive throttling based on remaining time
        if (this.getRemainingTimeMs() < 120000) {
          this.context.log("Running low on time, reducing batch processing speed");
        }

      } catch (error) {
        this.context.log.error(`Error in batch ${batchNumber}: ${error.message}`);
        this.errorCount++;
        this.errors.push({
          batch: batchNumber,
          error: error.message,
          timestamp: new Date().toISOString()
        });

        // Handle throttling (429)
        if (error.code === 429) {
          const retryAfterMs = (error.retryAfterInMs || 1000);
          this.context.log(`Throttled. Waiting ${retryAfterMs}ms before retry`);
          if (this.getRemainingTimeMs() > retryAfterMs + 30000) {
            await this.delay(retryAfterMs);
            continue; // Retry the same batch
          } else {
            // Not enough time to wait and retry, save checkpoint and exit
            break;
          }
        }

        // For other transient errors, save checkpoint and continue
        if (this.errorCount > 10) {
          this.context.log.error("Too many errors, stopping processing");
          break;
        }
      }
    }

    const isComplete = !hasMoreResults;

    // Final checkpoint
    await this.checkpointManager.saveCheckpoint(jobId, {
      continuationToken: continuationToken,
      processedCount: this.processedCount,
      batchNumber: batchNumber,
      status: isComplete ? "completed" : "paused",
      lastProcessedAt: new Date().toISOString(),
      errorCount: this.errorCount
    });

    if (isComplete) {
      // Clean up checkpoint on completion
      await this.checkpointManager.deleteCheckpoint(jobId);
    }

    return {
      jobId,
      status: isComplete ? "completed" : "paused",
      processedCount: this.processedCount,
      errorCount: this.errorCount,
      errors: this.errors.slice(0, 10), // Return first 10 errors
      batchesProcessed: batchNumber,
      continuationToken: isComplete ? null : continuationToken,
      executionTimeMs: Date.now() - this.startTime,
      remainingTimeMs: this.getRemainingTimeMs()
    };
  }

  async processItemsBatch(items, container) {
    const concurrency = 10;
    const chunks = [];

    for (let i = 0; i < items.length; i += concurrency) {
      chunks.push(items.slice(i, i + concurrency));
    }

    for (const chunk of chunks) {
      if (!this.shouldContinueProcessing()) break;

      const results = await Promise.allSettled(
        chunk.map(item => this.processItem(item, container))
      );

      for (const result of results) {
        if (result.status === "fulfilled") {
          this.processedCount++;
        } else {
          this.errorCount++;
          this.errors.push({
            error: result.reason?.message || "Unknown error",
            timestamp: new Date().toISOString()
          });
        }
      }
    }
  }

  async processItem(item, container) {
    const processingType = this.config.processingType || "transform";

    switch (processingType) {
      case "transform":
        return this.transformItem(item, container);
      case "aggregate":
        return this.aggregateItem(item);
      case "validate":
        return this.validateItem(item);
      case "enrich":
        return this.enrichItem(item, container);
      default:
        return this.transformItem(item, container);
    }
  }

  async transformItem(item, container) {
    // Apply transformation logic
    const transformed = {
      ...item,
      processedAt: new Date().toISOString(),
      _processed: true,
      _checksum: crypto.createHash("sha256").update(JSON.stringify(item)).digest("hex")
    };

    // Write back to Cosmos DB with optimistic concurrency
    await container.items.upsert(transformed, {
      accessCondition: {
        type: "IfMatch",
        condition: item._etag
      }
    });

    return transformed;
  }

  async aggregateItem(item) {
    // Aggregation logic - collect metrics
    return {
      id: item.id,
      aggregated: true
    };
  }

  async validateItem(item) {
    // Validation logic
    const isValid = item.id && item.partitionKey;
    if (!isValid) {
      throw new Error(`Validation failed for item ${item.id}`);
    }
    return { id: item.id, valid: true };
  }

  async enrichItem(item, container) {
    // Enrichment logic
    const enriched = {
      ...item,
      enrichedAt: new Date().toISOString(),
      _enriched: true
    };

    await container.items.upsert(enriched);
    return enriched;
  }

  delay(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  shutdown() {
    this.isShuttingDown = true;
    this.context.log("Graceful shutdown initiated");
  }
}

// Security: Cosmos DB client singleton with secure configuration
let cosmosClientInstance = null;

function getCosmosClient() {
  if (!cosmosClientInstance) {
    const endpoint = process.env.COSMOS_DB_ENDPOINT;
    const key = process.env.COSMOS_DB_KEY;
    const connectionString = process.env.COSMOS_DB_CONNECTION_STRING;

    if (!endpoint && !connectionString) {
      throw new Error("Cosmos DB configuration missing. Set COSMOS_DB_ENDPOINT and COSMOS_DB_KEY or COSMOS_DB_CONNECTION_STRING");
    }

    const clientOptions = {
      connectionPolicy: {
        requestTimeout: 30000,
        retryOptions: {
          maxRetryAttemptCount: 5,
          fixedRetryIntervalInMilliseconds: 1000,
          maxWaitTimeInSeconds: 30
        },
        enableEndpointDiscovery: true,
        preferredLocations: process.env.COSMOS_DB_PREFERRED_REGIONS
          ? process.env.COSMOS_DB_PREFERRED_REGIONS.split(",")
          : []
      },
      consistencyLevel: "Session"
    };

    if (connectionString) {
      cosmosClientInstance = new CosmosClient(connectionString);
    } else {
      cosmosClientInstance = new CosmosClient({
        endpoint,
        key,
        ...clientOptions
      });
    }
  }

  return cosmosClientInstance;
}

// Security: Extract client identifier for rate limiting
function getClientIdentifier(req) {
  // Use function key hash or IP as client identifier
  const authHeader = req.headers["x-functions-key"] || req.headers["x-ms-client-principal-id"] || "";
  const ip = req.headers["x-forwarded-for"] || req.headers["x-real-ip"] || "unknown";
  return crypto.createHash("sha256").update(`${authHeader}:${ip}`).digest("hex").substring(0, 16);
}

// Global request tracker instance
const requestTracker = new RequestTracker();

// Main function handler
module.exports = async function (context, req) {
  const clientId = getClientIdentifier(req);
  let processor = null;

  // Set up graceful shutdown handler
  const shutdownHandler = () => {
    if (processor) {
      processor.shutdown();
    }
  };

  process.on("SIGTERM", shutdownHandler);
  process.on("SIGINT", shutdownHandler);

  try {
    // Rate limiting check
    requestTracker.checkRateLimit(clientId);

    // Validate and sanitize input
    const validatedBody = InputValidator.validateBatchRequest(req.body || {});

    const config = {
      databaseId: validatedBody.databaseId || process.env.COSMOS_DB_DATABASE || "batch-processing-db",
      containerId: validatedBody.containerId || process.env.COSMOS_DB_CONTAINER || "data-container",
      query: validatedBody.query || "SELECT * FROM c WHERE NOT IS_DEFINED(c._processed) OR c._processed = false",
      batchSize: validatedBody.batchSize || 500,
      continuationToken: validatedBody.continuationToken || undefined,
      processingType: validatedBody.processingType || "transform"
    };

    // Generate or use provided job ID
    const jobId = req.headers["x-job-id"] || crypto.randomUUID();

    // Validate job ID format
    if (!/^[a-zA-Z0-9-]{1,128}$/.test(jobId)) {
      context.res = {
        status: 400,
        headers: { "Content-Type": "application/json" },
        body: { error: "Invalid job ID format" }
      };
      return;
    }

    const cosmosClient = getCosmosClient();

    processor = new BatchProcessor(cosmosClient, config, context);
    await processor.initialize();

    context.log(`Batch processing started. Job ID: ${jobId}, Config: ${JSON.stringify({
      databaseId: config.databaseId,
      containerId: config.containerId,
      batchSize: config.batchSize,
      processingType: config.processingType
    })}`);

    const result = await processor.processDataset(jobId);

    context.log(`Batch processing finished. Status: ${result.status}, Processed: ${result.processedCount}, Errors: ${result.errorCount}, Time: ${result.executionTimeMs}ms`);

    const statusCode = result.status === "completed" ? 200 : 202;

    context.res = {
      status: statusCode,
      headers: {
        "Content-Type": "application/json",
        "X-Job-Id": jobId,
        "X-Processing-Status": result.status,
        "X-Processed-Count": result.processedCount.toString()
      },
      body: {
        success: true,
        ...result
      }
    };

  } catch (error) {
    context.log.error(`Batch processing error: ${error.message}`);
    context.log.error(error.stack);

    let statusCode = 500;
    let errorMessage = "Internal server error during batch processing";

    if (error.message.includes("Rate limit")) {
      statusCode = 429;
      errorMessage = error.message;
    } else if (error.message.includes("Too many concurrent")) {
      statusCode = 429;
      errorMessage = error.message;
    } else if (error.message.includes("Invalid") || error.message.includes("Unknown fields") || error.message.includes("malicious")) {
      statusCode = 400;
      errorMessage = error.message;
    } else if (error.message.includes("configuration missing")) {
      statusCode = 503;
      errorMessage = "Service configuration error";
    }

    context.res = {
      status: statusCode,
      headers: { "Content-Type": "application/json" },
      body: {
        success: false,
        error: errorMessage,
        // Don't leak internal error details in production
        ...(process.env.NODE_ENV !== "production" && { details: error.message })
      }
    };
  } finally {
    requestTracker.releaseRequest(clientId);
    process.removeListener("SIGTERM", shutdownHandler);
    process.removeListener("SIGINT", shutdownHandler);
  }
};

